import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, ChartsXAxis, ChartsYAxis, BarPlot, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface DepartmentData {
  name: string;
  allocation: number;
}

interface WidgetData {
  departments: DepartmentData[];
}

interface MetaData {
  theme: string;
  primaryColor: string;
  accentColor: string;
}

export default function Widget() {
  const widgetData = response.data as WidgetData;
  const metaData = response.meta as MetaData;
  const clipPathId = useId();

  const departments = widgetData.departments.slice(0, 5); // Limit to top 5 departments by allocation
  const colors = ['#3B82F6', '#F59E0B'];

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#000', color: '#FFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={700} sx={{ color: metaData.primaryColor }}>
              Budget Allocation
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Top 5 Departments
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: departments.map(d => d.allocation),
                  color: metaData.accentColor,
                  label: 'Allocation',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: departments.map(d => d.name),
                  id: 'departments',
                },
              ]}
              yAxis={[{ id: 'allocation' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="departments"
                tickLabelStyle={{ fontSize: 10, fill: '#9CA3AF' }}
              />
              <ChartsYAxis
                axisId="allocation"
                tickLabelStyle={{ fontSize: 10, fill: '#9CA3AF' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
